import React, { useMemo } from 'react';
import { cn } from '@/common/lib/utils';
import { useAuthStore } from '@/store/authStore';

/**
 * Mention format from backend: @[DisplayName|UUID]
 * Special: @[all|all] for mentioning everyone
 *
 * This component parses message content and renders mention tags
 * as highlighted inline chips.
 */

// Regex to match @[DisplayName|UUID] patterns (same as MentionParser.java)
const MENTION_REGEX = /@\[([^|]*?)\|([^\]]*?)\]/g;

interface MentionSegment {
    type: 'text' | 'mention';
    value: string;
    userId?: string;
    displayName?: string;
    isSelf?: boolean;
    isAll?: boolean;
}

interface MentionTextProps {
    content: string;
    className?: string;
    isOwnMessage?: boolean;
}

export const MentionText: React.FC<MentionTextProps> = ({ content, className, isOwnMessage = false }) => {
    const currentUser = useAuthStore(state => state.user);

    const segments = useMemo((): MentionSegment[] => {
        const result: MentionSegment[] = [];
        let lastIndex = 0;

        // Reset regex state
        MENTION_REGEX.lastIndex = 0;

        let match: RegExpExecArray | null;
        while ((match = MENTION_REGEX.exec(content)) !== null) {
            // Push text before the mention
            if (match.index > lastIndex) {
                result.push({
                    type: 'text',
                    value: content.slice(lastIndex, match.index)
                });
            }

            const displayName = match[1];
            const userId = match[2];
            const isAll = userId === 'all';
            const isSelf = !isAll && userId === currentUser?.userId;

            result.push({
                type: 'mention',
                value: `@${displayName}`,
                userId,
                displayName,
                isSelf,
                isAll
            });

            lastIndex = match.index + match[0].length;
        }

        // Push remaining text
        if (lastIndex < content.length) {
            result.push({
                type: 'text',
                value: content.slice(lastIndex)
            });
        }

        return result;
    }, [content, currentUser?.userId]);

    // No mentions found — return plain text
    const hasMentions = segments.some(s => s.type === 'mention');
    if (!hasMentions) {
        return <span className={className}>{content}</span>;
    }

    return (
        <span className={className}>
            {segments.map((segment, index) => {
                if (segment.type === 'text') {
                    return <span key={index}>{segment.value}</span>;
                }

                // Mention chip
                return (
                    <span
                        key={index}
                        className={cn(
                            "inline-flex items-center px-1.5 py-0.5 rounded-md font-bold text-xs cursor-pointer transition-all duration-200",
                            segment.isAll
                                ? "bg-amber-500/20 text-amber-400 hover:bg-amber-500/30 border border-amber-500/30"
                                : segment.isSelf
                                    ? isOwnMessage
                                        ? "bg-white/25 text-white hover:bg-white/35 border border-white/30"
                                        : "bg-primary/20 text-primary hover:bg-primary/30 border border-primary/30 ring-1 ring-primary/20"
                                    : isOwnMessage
                                        ? "bg-white/15 text-white/90 hover:bg-white/25"
                                        : "bg-primary/10 text-primary/80 hover:bg-primary/20"
                        )}
                        title={segment.isAll ? 'Tất cả mọi người' : segment.displayName}
                    >
                        {segment.value}
                    </span>
                );
            })}
        </span>
    );
};

/**
 * Utility: Insert a mention tag into content string at cursor position.
 * Returns the new content and the new cursor position.
 */
export const insertMention = (
    content: string,
    cursorPos: number,
    userId: string,
    displayName: string
): { newContent: string; newCursorPos: number } => {
    // Find the '@' trigger position before cursor
    const beforeCursor = content.slice(0, cursorPos);
    const atIndex = beforeCursor.lastIndexOf('@');

    if (atIndex === -1) {
        return { newContent: content, newCursorPos: cursorPos };
    }

    const mentionTag = `@[${displayName}|${userId}] `;
    const before = content.slice(0, atIndex);
    const after = content.slice(cursorPos);
    const newContent = before + mentionTag + after;
    const newCursorPos = before.length + mentionTag.length;

    return { newContent, newCursorPos };
};

/**
 * Utility: Extract the current mention query (text after '@') for autocomplete.
 * Returns null if user is not currently typing a mention.
 */
export const getMentionQuery = (content: string, cursorPos: number): string | null => {
    const beforeCursor = content.slice(0, cursorPos);
    const atIndex = beforeCursor.lastIndexOf('@');

    if (atIndex === -1) return null;

    // Ensure '@' is at the start of a word (preceded by space, newline, or start of string)
    if (atIndex > 0 && !/\s/.test(beforeCursor[atIndex - 1])) return null;

    const query = beforeCursor.slice(atIndex + 1);

    // If query contains space or newline, user has moved past the mention
    if (/[\n\r]/.test(query)) return null;

    return query;
};

import React from 'react';
import type { Message } from '../../types/messenger.types';
import { useAuthStore } from '@/store/authStore';
import { format } from 'date-fns';
import { cn } from '@/common/lib/utils';
import { MoreHorizontal, Reply, Copy, Trash2 } from 'lucide-react';
import { ReactionPicker, ReactionDisplay } from '@/components/chat/ReactionPicker';
import { MentionText } from './MentionText';
import { PollCard } from '../Poll/PollCard';


interface MessageItemProps {
    message: Message;
    showAvatar: boolean;
    onAction?: (action: string, messageId: string) => void;
}

export const MessageItem: React.FC<MessageItemProps> = ({ message, showAvatar, onAction }) => {
    const { user } = useAuthStore();
    const [isMenuOpen, setIsMenuOpen] = React.useState(false);
    const isOwn = message.sender.userId === user?.userId;
    const isPoll = message.type === 'POLL' && message.poll;

    const handleAction = (action: string) => {
        setIsMenuOpen(false);
        if (onAction) {
            onAction(action, message.messageId);
        }
    };

    return (
        <div className={cn(
            "flex w-full gap-3 animate-in fade-in duration-300",
            isOwn ? "flex-row-reverse" : "flex-row"
        )}>
            {/* Avatar Container */}
            <div className="w-10 h-10 flex-shrink-0 mt-auto">
                {showAvatar && !isOwn && (
                    <div className="w-10 h-10 rounded-xl overflow-hidden border-2 border-primary/20 bg-primary/10 flex items-center justify-center font-black text-primary text-xs uppercase">
                        {message.sender.avatarUrl ? (
                            <img src={message.sender.avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                        ) : (
                            message.sender.displayName?.charAt(0)
                        )}
                    </div>
                )}
            </div>

            {/* Message Content Area */}
            <div className={cn(
                "flex flex-col",
                isPoll ? "max-w-[85%]" : "max-w-[70%]",
                isOwn ? "items-end" : "items-start"
            )}>
                {/* Sender Name for non-DMs/Group chats if needed */}
                {showAvatar && !isOwn && (
                    <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60 mb-1 ml-1">
                        {message.sender.displayName}
                    </span>
                )}

                {/* Message Bubble & Actions Wrapper */}
                <div className={cn(
                    "relative group flex items-center gap-2",
                    isOwn ? "flex-row-reverse" : "flex-row"
                )}>
                    {/* Message Bubble */}
                    {isPoll ? (
                        /* Poll message — render PollCard instead of text bubble */
                        <PollCard poll={message.poll!} />
                    ) : (
                        <div className={cn(
                            "px-4 py-3 rounded-3xl relative transition-all duration-300",
                            isOwn
                                ? "bg-primary text-primary-foreground rounded-tr-none neo-shadow hover:translate-x-[-2px] hover:translate-y-[-2px]"
                                : "glass rounded-tl-none hover:bg-background/40"
                        )}>
                            <MentionText
                                content={message.content}
                                isOwnMessage={isOwn}
                                className="text-sm font-medium leading-relaxed whitespace-pre-wrap break-words"
                            />

                            {/* Status / Time Overlay (Shown on hover) */}
                            <div className={cn(
                                "absolute -bottom-5 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap",
                                isOwn ? "right-2" : "left-2"
                            )}>
                                <span className="text-[9px] font-bold uppercase tracking-tighter opacity-70">
                                    {format(new Date(message.createdAt as unknown as string | number | Date), 'HH:mm')}
                                </span>
                                {isOwn && (
                                    <span className="text-[9px] font-black uppercase text-primary">
                                        {message.status === 'sending' ? 'Đang gửi...' : 'Đã gửi'}
                                    </span>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Actions Menu */}
                    <div className={cn(
                        "relative opacity-0 group-hover:opacity-100 transition-opacity duration-200 flex items-center gap-0.5",
                        isMenuOpen ? "opacity-100 z-10" : ""
                    )}>
                        {/* Reaction Picker */}
                        <ReactionPicker
                            conversationId={message.conversationId}
                            messageId={message.messageId}
                        />

                        <button
                            onClick={() => setIsMenuOpen(!isMenuOpen)}
                            className="p-1 hover:bg-primary/10 rounded-full text-muted-foreground hover:text-primary transition-colors"
                        >
                            <MoreHorizontal size={16} />
                        </button>

                        {isMenuOpen && (
                            <div className={cn(
                                "absolute top-full mt-1 bg-card glass border border-border/50 rounded-2xl neo-shadow overflow-hidden min-w-[150px] animate-in zoom-in-95 duration-200 z-50",
                                isOwn ? "right-0" : "left-0"
                            )}>
                                <div className="p-1.5 space-y-0.5 flex flex-col items-stretch text-left">
                                    <button
                                        onClick={() => handleAction('reply')}
                                        className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-primary/10 text-foreground transition-colors text-xs font-bold"
                                    >
                                        <Reply size={14} className="text-primary" />
                                        <span>Trả lời</span>
                                    </button>
                                    <button
                                        onClick={() => handleAction('copy')}
                                        className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-primary/10 text-foreground transition-colors text-xs font-bold"
                                    >
                                        <Copy size={14} className="text-primary" />
                                        <span>Sao chép</span>
                                    </button>
                                    {isOwn && (
                                        <>
                                            <div className="h-px bg-border/50 my-1 mx-2" />
                                            <button
                                                onClick={() => handleAction('delete')}
                                                className="flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-destructive/10 text-destructive transition-colors text-xs font-bold"
                                            >
                                                <Trash2 size={14} />
                                                <span>Xóa bộ nhớ</span>
                                            </button>
                                        </>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>

                {/* Reactions Display */}
                {message.reactions && message.reactions.length > 0 && (
                    <div className={cn("px-2", isOwn ? "flex justify-end" : "")}>
                        <ReactionDisplay
                            reactions={message.reactions}
                            conversationId={message.conversationId}
                            messageId={message.messageId}
                        />
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useMemo, useCallback } from 'react';
import { cn } from '@/common/lib/utils';
import { Check, Clock, Lock, BarChart3, Users, Trash2, ChevronDown, ChevronUp } from 'lucide-react';
import { useAuthStore } from '@/store/authStore';
import { votePoll, closePoll, removePollVote } from '../../api/poll.api';
import type { PollData } from '../../types/messenger.types';
import { formatDistanceToNow, isPast } from 'date-fns';
import { vi } from 'date-fns/locale';

interface PollCardProps {
    poll: PollData;
    onUpdate?: (updatedPoll: PollData) => void;
}

export const PollCard: React.FC<PollCardProps> = ({ poll, onUpdate }) => {
    const currentUser = useAuthStore(state => state.user);
    const [selectedOptions, setSelectedOptions] = useState<string[]>(poll.currentUserVotes ?? []);
    const [isVoting, setIsVoting] = useState(false);
    const [showVoters, setShowVoters] = useState(false);
    const [localPoll, setLocalPoll] = useState(poll);

    const isCreator = currentUser?.userId === localPoll.createdBy;
    const hasVoted = localPoll.currentUserVotes.length > 0;
    const isExpired = localPoll.expiresAt ? isPast(new Date(localPoll.expiresAt)) : false;
    const isClosed = localPoll.isClosed || isExpired;

    // Sort options by vote count descending for display
    const sortedOptions = useMemo(() =>
        [...localPoll.options].sort((a, b) => b.voteCount - a.voteCount),
        [localPoll.options]
    );

    // Find the winning option(s)
    const maxVotes = useMemo(() =>
        Math.max(...localPoll.options.map(o => o.voteCount), 0),
        [localPoll.options]
    );

    const toggleOption = (option: string) => {
        if (isClosed) return;

        if (localPoll.isMultipleChoice) {
            setSelectedOptions(prev =>
                prev.includes(option)
                    ? prev.filter(o => o !== option)
                    : [...prev, option]
            );
        } else {
            setSelectedOptions(prev =>
                prev.includes(option) ? [] : [option]
            );
        }
    };

    const handleVote = useCallback(async () => {
        if (selectedOptions.length === 0 || isClosed) return;
        setIsVoting(true);
        try {
            await votePoll(localPoll.pollId, selectedOptions);
            // Optimistic update
            setLocalPoll(prev => ({
                ...prev,
                currentUserVotes: selectedOptions,
                totalVotes: prev.totalVotes + (hasVoted ? 0 : 1)
            }));
        } catch (err) {
            console.error('[PollCard] Vote failed:', err);
        } finally {
            setIsVoting(false);
        }
    }, [selectedOptions, localPoll.pollId, hasVoted, isClosed]);

    const handleRemoveVote = useCallback(async () => {
        setIsVoting(true);
        try {
            await removePollVote(localPoll.pollId);
            setSelectedOptions([]);
            setLocalPoll(prev => ({
                ...prev,
                currentUserVotes: [],
                totalVotes: Math.max(0, prev.totalVotes - 1)
            }));
        } catch (err) {
            console.error('[PollCard] Remove vote failed:', err);
        } finally {
            setIsVoting(false);
        }
    }, [localPoll.pollId]);

    const handleClosePoll = useCallback(async () => {
        try {
            await closePoll(localPoll.pollId);
            setLocalPoll(prev => ({ ...prev, isClosed: true }));
        } catch (err) {
            console.error('[PollCard] Close poll failed:', err);
        }
    }, [localPoll.pollId]);

    return (
        <div className="w-full max-w-sm bg-card/80 backdrop-blur-md border border-border/50 rounded-2xl overflow-hidden transition-all duration-300 hover:border-primary/20">
            {/* Poll Header */}
            <div className="px-4 pt-4 pb-2">
                <div className="flex items-start gap-2 mb-1">
                    <BarChart3 size={16} className="text-primary mt-0.5 flex-shrink-0" />
                    <h4 className="text-sm font-black leading-snug">{localPoll.question}</h4>
                </div>

                <div className="flex items-center gap-2 text-[10px] text-muted-foreground font-medium mt-1">
                    <span className={cn(
                        "px-1.5 py-0.5 rounded-md",
                        localPoll.isMultipleChoice ? "bg-blue-500/10 text-blue-400" : "bg-primary/10 text-primary"
                    )}>
                        {localPoll.isMultipleChoice ? 'Chọn nhiều' : 'Chọn một'}
                    </span>

                    {localPoll.expiresAt && (
                        <span className={cn(
                            "flex items-center gap-1 px-1.5 py-0.5 rounded-md",
                            isExpired ? "bg-destructive/10 text-destructive" : "bg-amber-500/10 text-amber-500"
                        )}>
                            <Clock size={10} />
                            {isExpired
                                ? 'Đã hết hạn'
                                : `Còn ${formatDistanceToNow(new Date(localPoll.expiresAt), { locale: vi })}`
                            }
                        </span>
                    )}

                    {isClosed && !isExpired && (
                        <span className="flex items-center gap-1 px-1.5 py-0.5 rounded-md bg-muted text-muted-foreground">
                            <Lock size={10} />
                            Đã đóng
                        </span>
                    )}
                </div>
            </div>

            {/* Options */}
            <div className="px-3 py-2 space-y-1.5">
                {sortedOptions.map((option) => {
                    const isSelected = selectedOptions.includes(option.option);
                    const isUserVoted = localPoll.currentUserVotes.includes(option.option);
                    const isWinning = option.voteCount === maxVotes && maxVotes > 0;

                    return (
                        <button
                            key={option.option}
                            onClick={() => toggleOption(option.option)}
                            disabled={isClosed}
                            className={cn(
                                "w-full relative overflow-hidden rounded-xl transition-all duration-300 text-left group",
                                isClosed
                                    ? "cursor-default"
                                    : "cursor-pointer hover:scale-[1.01] active:scale-[0.99]",
                                isSelected && !isClosed && "ring-2 ring-primary/40"
                            )}
                        >
                            {/* Progress bar background */}
                            <div
                                className={cn(
                                    "absolute inset-0 rounded-xl transition-all duration-500 ease-out",
                                    isWinning && hasVoted
                                        ? "bg-primary/15"
                                        : isUserVoted
                                            ? "bg-primary/10"
                                            : "bg-muted/40"
                                )}
                                style={{ width: `${hasVoted || isClosed ? option.percentage : 0}%` }}
                            />

                            {/* Content */}
                            <div className="relative flex items-center gap-2.5 px-3 py-2.5 border border-border/30 rounded-xl">
                                {/* Checkbox / Radio indicator */}
                                <div className={cn(
                                    "w-5 h-5 rounded-md flex items-center justify-center flex-shrink-0 border-2 transition-all duration-200",
                                    isSelected || isUserVoted
                                        ? "bg-primary border-primary text-primary-foreground"
                                        : "border-border/60 group-hover:border-primary/40"
                                )}>
                                    {(isSelected || isUserVoted) && <Check size={12} strokeWidth={3} />}
                                </div>

                                {/* Option text */}
                                <span className={cn(
                                    "flex-1 text-sm font-semibold truncate",
                                    isWinning && hasVoted && "text-primary"
                                )}>
                                    {option.option}
                                </span>

                                {/* Vote count & percentage */}
                                {(hasVoted || isClosed) && (
                                    <div className="flex items-center gap-1.5 flex-shrink-0">
                                        <span className="text-xs font-black text-muted-foreground">
                                            {option.voteCount}
                                        </span>
                                        <span className={cn(
                                            "text-[10px] font-bold px-1.5 py-0.5 rounded-md",
                                            isWinning
                                                ? "bg-primary/20 text-primary"
                                                : "bg-muted/60 text-muted-foreground"
                                        )}>
                                            {option.percentage.toFixed(0)}%
                                        </span>
                                    </div>
                                )}
                            </div>
                        </button>
                    );
                })}
            </div>

            {/* Footer Actions */}
            <div className="px-4 py-3 border-t border-border/30 flex items-center justify-between">
                <div className="flex items-center gap-1.5 text-[10px] text-muted-foreground font-medium">
                    <Users size={12} />
                    <span>{localPoll.totalVotes} phiếu bầu</span>
                </div>

                <div className="flex items-center gap-2">
                    {/* Show/hide voters */}
                    {hasVoted && localPoll.totalVotes > 0 && (
                        <button
                            onClick={() => setShowVoters(!showVoters)}
                            className="text-[10px] font-bold text-muted-foreground hover:text-primary transition-colors flex items-center gap-0.5"
                        >
                            Chi tiết
                            {showVoters ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
                        </button>
                    )}

                    {/* Remove vote */}
                    {hasVoted && !isClosed && (
                        <button
                            onClick={() => void handleRemoveVote()}
                            disabled={isVoting}
                            className="text-[10px] font-bold text-destructive/70 hover:text-destructive transition-colors flex items-center gap-0.5"
                        >
                            <Trash2 size={10} />
                            Hủy phiếu
                        </button>
                    )}

                    {/* Close poll (creator only) */}
                    {isCreator && !isClosed && (
                        <button
                            onClick={() => void handleClosePoll()}
                            className="text-[10px] font-bold text-amber-500 hover:text-amber-400 transition-colors flex items-center gap-0.5"
                        >
                            <Lock size={10} />
                            Đóng
                        </button>
                    )}

                    {/* Vote button */}
                    {!isClosed && selectedOptions.length > 0 && (
                        <button
                            onClick={() => void handleVote()}
                            disabled={isVoting}
                            className="px-3 py-1.5 text-[10px] font-black bg-primary text-primary-foreground rounded-lg neo-shadow hover:translate-x-[0.5px] hover:translate-y-[0.5px] transition-all disabled:opacity-40"
                        >
                            {isVoting ? 'Đang gửi...' : hasVoted ? 'Đổi phiếu' : 'Bình chọn'}
                        </button>
                    )}
                </div>
            </div>

            {/* Voters detail panel */}
            {showVoters && (
                <div className="px-4 pb-3 animate-in slide-in-from-top-2 fade-in duration-200">
                    <div className="bg-background/50 rounded-xl p-3 space-y-2 max-h-32 overflow-y-auto custom-scrollbar">
                        {sortedOptions.map(option => (
                            option.voteCount > 0 && (
                                <div key={option.option} className="flex items-start gap-2">
                                    <span className="text-[10px] font-bold text-primary bg-primary/10 px-1.5 py-0.5 rounded-md whitespace-nowrap">
                                        {option.option}
                                    </span>
                                    <span className="text-[10px] text-muted-foreground">
                                        {option.voterIds.length} phiếu
                                    </span>
                                </div>
                            )
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};
